101→bool ULFPSkillComponent::ExecuteSkill(ULFPSkillBase* Skill, ALFPHexTile* TargetTile)
102→{
103→    ALFPTacticsUnit* OwnerUnit = Cast<ALFPTacticsUnit>(GetOwner());
104→    if (!OwnerUnit || !Skill) return false;
105→
106→    if (!OwnerUnit->IsEnemy())
107→    {
108→		// 检查技能是否可用
109→		if (!Skill->CanExecute(TargetTile)) return false;
110→    }
111→
112→    // 执行技能
113→    Skill->Execute(TargetTile);
114→
115→    // 更新技能优先级（降低已使用技能的优先级）
