317→FReply ULFPSkillSelectionWidget::NativeOnKeyDown(const FGeometry& InGeometry, const FKeyEvent& InKeyEvent)
318→{
319→    // 处理键盘输入
320→    if (InKeyEvent.GetKey() == EKeys::Escape)
321→    {
322→        OnCancelClicked();
323→        return FReply::Handled();
324→    }
325→    else if (InKeyEvent.GetKey() == EKeys::Enter || InKeyEvent.GetKey() == EKeys::SpaceBar)
326→    {
327→        OnConfirmClicked();
328→        return FReply::Handled();
329→    }
330→
331→    return Super::NativeOnKeyDown(InGeometry, InKeyEvent);
