408→TArray<ULFPSkillBase*> ULFPSkillSelectionWidget::GetFilteredSkills(ALFPTacticsUnit* Unit) const
409→{
410→    TArray<ULFPSkillBase*> FilteredSkills;
411→
412→    if (!Unit) return FilteredSkills;
413→
414→    // 获取所有可用技能
415→    TArray<ULFPSkillBase*> AllSkills = Unit->GetAvailableSkills();
416→
417→    // 如果没有过滤条件，返回所有技能
418→    if (SkillFilterTags.IsEmpty())
419→    {
420→        return AllSkills;
421→    }
422→
423→    // 应用过滤条件
424→    for (ULFPSkillBase* Skill : AllSkills)
425→    {
426→        if (Skill && Skill->SkillTags.HasAny(SkillFilterTags))
427→        {
428→            FilteredSkills.Add(Skill);
429→        }
430→    }
431→
432→    return FilteredSkills;
433→}
