445→void ULFPSkillSelectionWidget::SortSkills(ESkillSortMethod SortMethod)
446→{
447→    if (!OwnerUnit) return;
448→
449→    // 获取当前显示的技能
450→    TArray<ULFPSkillBase*> CurrentSkills;
451→    for (ULFPSkillButtonWidget* Button : SkillButtons)
452→    {
453→        if (Button && Button->GetSkill())
454→        {
455→            CurrentSkills.Add(Button->GetSkill());
456→        }
457→    }
458→
459→    // 根据排序方法排序
460→    switch (SortMethod)
461→    {
462→    case ESkillSortMethod::ByName:
463→        CurrentSkills.Sort([](const ULFPSkillBase& A, const ULFPSkillBase& B) {
464→            return A.SkillName.ToString() < B.SkillName.ToString();
465→            });
466→        break;
467→
468→    case ESkillSortMethod::ByCooldown:
469→        CurrentSkills.Sort([](const ULFPSkillBase& A, const ULFPSkillBase& B) {
470→            return A.CurrentCooldown < B.CurrentCooldown;
471→            });
472→        break;
473→
474→    case ESkillSortMethod::ByCost:
475→        CurrentSkills.Sort([](const ULFPSkillBase& A, const ULFPSkillBase& B) {
476→            return A.ActionPointCost < B.ActionPointCost;
477→            });
478→        break;
479→
480→    case ESkillSortMethod::ByType:
481→        // 需要添加技能类型属性，如SkillType字段
482→        // CurrentSkills.Sort([](const ULFPSkillBase& A, const ULFPSkillBase& B) {
483→        //     return A.SkillType < B.SkillType;
484→        // });
485→        break;
486→    }
487→
488→    // 重新排列所有技能按钮
489→    if (SkillGrid)
490→    {
491→        SkillGrid->ClearChildren();
492→
493→        int32 Row = 0;
494→        int32 Column = 0;
495→
496→        for (ULFPSkillBase* Skill : CurrentSkills)
497→        {
498→            // 找到对应的按钮
499→            for (ULFPSkillButtonWidget* Button : SkillButtons)
500→            {
501→                if (Button && Button->GetSkill() == Skill)
502→                {
503→                    SkillGrid->AddChildToUniformGrid(Button, Row, Column);
504→
505→                    Column++;
506→                    if (Column >= MaxColumns)
507→                    {
508→                        Column = 0;
509→                        Row++;
510→                    }
511→
512→                    break;
513→                }
514→            }
515→        }
516→    }
517→}
