}

void ULFPSkillSelectionWidget::OnSkillUnhovered()
{
    // 如果之前有选中的技能，显示选中技能的详情
    if (SelectedSkill)
    {
        UpdateSkillDetails(SelectedSkill);
    }
    else
    {
        // 隐藏详情面板
        if (SkillDetailsPanel)
        {
            SkillDetailsPanel->SetVisibility(ESlateVisibility::Collapsed);
        }
    }
}

