		break;
	case EBattlePhase::BP_ActionPhase:
		PhaseString = TEXT("Action Phase");
		break;
	case EBattlePhase::BP_RoundEnd:
		PhaseString = TEXT("Round End");
		break;
	default:
		PhaseString = TEXT("");
		break;
	}

	PhaseText->SetText(FText::FromString(PhaseString));
}

