void ULFPSkillSelectionWidget::OnSkillSelected(ULFPSkillBase* Skill)
{
    if (!Skill || !OwnerUnit) return;

    SelectedSkill = Skill;

    // 更新技能详情
    UpdateSkillDetails(Skill);

    // 显示详情面板
    if (SkillDetailsPanel)
    {
        SkillDetailsPanel->SetVisibility(ESlateVisibility::Visible);
